{
    "level": "A2",
    "intro": "W tym temacie nauczysz się różnicy między przymiotnikami z końcówką <strong>-ed</strong> i <strong>-ing</strong>: <strong>-ed</strong> opisuje uczucie człowieka, a <strong>-ing</strong> rzecz, sytuację albo osobę, która to uczucie wywołuje.",
    "rules": [
        {
            "label": "UCZUCIE",
            "color": "emerald",
            "text": "<strong>-ed</strong> = jak ktoś się czuje:",
            "example": "I am bored."
        },
        {
            "label": "PRZYCZYNA",
            "color": "blue",
            "text": "<strong>-ing</strong> = co wywołuje to uczucie:",
            "example": "The film is boring."
        },
        {
            "label": "TEN SAM RDZEŃ",
            "color": "amber",
            "text": "Para często pochodzi od tego samego rdzenia: bored / boring, interested / interesting, tired / tiring.",
            "example": "She is interested in an interesting book."
        }
    ]
}

{
    "title": "1. Typowe pary",
    "intro": "Najlepiej uczyć się tych przymiotników parami.",
    "items": [
        {
            "label": "uczucie / przyczyna",
            "title": "bored / boring",
            "subtitle": "I am bored. / The lesson is boring."
        },
        {
            "label": "uczucie / przyczyna",
            "title": "interested / interesting",
            "subtitle": "We are interested. / The topic is interesting."
        },
        {
            "label": "uczucie / przyczyna",
            "title": "excited / exciting",
            "subtitle": "They are excited. / The trip is exciting."
        },
        {
            "label": "uczucie / przyczyna",
            "title": "tired / tiring",
            "subtitle": "I am tired. / The journey is tiring."
        }
    ]
}

{
    "title": "2. Jak to działa",
    "sections": [
        {
            "label": "Gdy mówimy o ludziach",
            "color": "emerald",
            "description": "Jeśli opisujesz <strong>emocję albo stan człowieka</strong>, zwykle potrzebujesz <strong>-ed</strong>.",
            "examples": [
                {
                    "en": "I am really tired after work.",
                    "ua": "Jestem naprawdę zmęczony po pracy."
                },
                {
                    "en": "She felt embarrassed in class.",
                    "ua": "Czuła się zawstydzona na lekcji."
                },
                {
                    "en": "We were surprised by the news.",
                    "ua": "Byliśmy zaskoczeni tą wiadomością."
                }
            ]
        },
        {
            "label": "Gdy mówimy o rzeczy albo sytuacji",
            "color": "blue",
            "description": "Jeśli coś <strong>wywołuje</strong> emocję, zwykle potrzebujesz <strong>-ing</strong>.",
            "examples": [
                {
                    "en": "The lecture was boring.",
                    "ua": "Wykład był nudny."
                },
                {
                    "en": "It was an exciting match.",
                    "ua": "To był ekscytujący mecz."
                },
                {
                    "en": "The instructions are confusing.",
                    "ua": "Instrukcje są mylące."
                }
            ]
        },
        {
            "label": "Porównaj parę",
            "color": "amber",
            "description": "Jedna końcówka zmienia całą logikę zdania.",
            "examples": [
                {
                    "en": "I am bored. / The film is boring.",
                    "ua": "Nudzę się. / Film jest nudny."
                },
                {
                    "en": "They are excited. / The trip is exciting.",
                    "ua": "Są podekscytowani. / Wyjazd jest ekscytujący."
                },
                {
                    "en": "He is confused. / The map is confusing.",
                    "ua": "On jest zdezorientowany. / Mapa jest myląca."
                }
            ],
            "note": "Najpierw zadaj sobie pytanie: to uczucie czy przyczyna uczucia?"
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Boring o osobie, która się nudzi.",
            "wrong": "I am boring.",
            "right": "✅ <span class=\"font-mono\">I am bored.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Bored o filmie albo lekcji.",
            "wrong": "The lesson is bored.",
            "right": "✅ <span class=\"font-mono\">The lesson is boring.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie pary.",
            "wrong": "She is interesting in art.",
            "right": "✅ <span class=\"font-mono\">She is interested in art.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "<strong>-ed</strong> opisuje uczucie albo stan człowieka.",
        "<strong>-ing</strong> opisuje rzecz, wydarzenie albo osobę, która wywołuje to uczucie.",
        "Ucz się par razem: bored / boring, excited / exciting, interested / interesting.",
        "Jeśli człowiek coś czuje, zwykle potrzebujesz <strong>-ed</strong>.",
        "Jeśli coś wywołuje emocję, zwykle potrzebujesz <strong>-ing</strong>."
    ]
}

